        if (this.isLeftHandTap)
        {
            return this.calculateEndX() - startNoteRenderer.smuflMetrics.leftHandTabTieWidth
        }
        return startNoteRenderer.x + startNoteRenderer!!.getNoteX(this.startNote, this.getStartNotePosition())
    }
    
    protected open fun getStartNotePosition(): com.omnifret.gplayer.rendering.NoteXPosition{
        return com.omnifret.gplayer.rendering.NoteXPosition.Center
    }
    
    protected override fun calculateStartY(): Double{
        var startNoteRenderer: com.omnifret.gplayer.rendering.LineBarRenderer = this.lookupStartBeatRenderer()
        if (this.isLeftHandTap)
        {
            return startNoteRenderer.y + startNoteRenderer.getNoteY(this.startNote, com.omnifret.gplayer.rendering.NoteYPosition.Center)
        }
        when (this.tieDirection)
        {
            com.omnifret.gplayer.rendering.utils.BeamDirection.Up -> 
            {
                return startNoteRenderer.y + startNoteRenderer!!.getNoteY(this.startNote, com.omnifret.gplayer.rendering.NoteYPosition.Top)
            }
            else -> 
            {
                return startNoteRenderer.y + startNoteRenderer.getNoteY(this.startNote, com.omnifret.gplayer.rendering.NoteYPosition.Bottom)
            }
        }
    }
    
    protected override fun calculateEndX(): Double{
        var endNoteRenderer: com.omnifret.gplayer.rendering.LineBarRenderer? = this.lookupEndBeatRenderer()
        if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(endNoteRenderer)))
        {
            return this.calculateStartY() + this.renderer.smuflMetrics.leftHandTabTieWidth
        }
        if (this.isLeftHandTap)
        {
            return endNoteRenderer!!.x + endNoteRenderer!!.getNoteX(this.endNote, com.omnifret.gplayer.rendering.NoteXPosition.Left)
        }
        return endNoteRenderer!!.x + endNoteRenderer!!.getNoteX(this.endNote, com.omnifret.gplayer.rendering.NoteXPosition.Center)
    }
    
    protected open fun getEndNotePosition(): com.omnifret.gplayer.rendering.NoteXPosition{
        return com.omnifret.gplayer.rendering.NoteXPosition.Center
    }
    
    protected override fun caclculateEndY(): Double{
        var endNoteRenderer: com.omnifret.gplayer.rendering.LineBarRenderer? = this.lookupEndBeatRenderer()
        if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(endNoteRenderer)))
        {
            return this.calculateStartY()
        }
        if (this.isLeftHandTap)
        {
            return endNoteRenderer!!.y + endNoteRenderer!!.getNoteY(this.endNote, com.omnifret.gplayer.rendering.NoteYPosition.Center)
        }
        when (this.tieDirection)
        {
            com.omnifret.gplayer.rendering.utils.BeamDirection.Up -> 
            {
                return endNoteRenderer!!.y + endNoteRenderer!!.getNoteY(this.endNote, com.omnifret.gplayer.rendering.NoteYPosition.Top)
            }
            else -> 
            {
                return endNoteRenderer!!.y + endNoteRenderer!!.getNoteY(this.endNote, com.omnifret.gplayer.rendering.NoteYPosition.Bottom)
            }
        }
    }
    
    protected override fun lookupEndBeatRenderer(): com.omnifret.gplayer.rendering.LineBarRenderer?{
        if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this.endNoteRenderer)))
        {
            this.endNoteRenderer = (this.renderer.scoreRenderer.layout!!.getRendererForBar(this.renderer.staff!!.staffId, this.endNote.beat.voice.bar) as com.omnifret.gplayer.rendering.LineBarRenderer?)
        }
        return this.endNoteRenderer
    }
    
    protected override fun lookupStartBeatRenderer(): com.omnifret.gplayer.rendering.LineBarRenderer{
        if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this.startNoteRenderer)))
        {
            this.startNoteRenderer = (this.renderer.scoreRenderer.layout!!.getRendererForBar(this.renderer.staff!!.staffId, this.startNote.beat.voice.bar)!! as com.omnifret.gplayer.rendering.LineBarRenderer)
        }
        return this.startNoteRenderer!!
    }
    
    protected override fun shouldDrawBendSlur(): Boolean{
        return false
    }
    
}

/**
 * A tie glyph for continued multi-system ties/slurs
 */
@kotlin.contracts.ExperimentalContracts
@kotlin.ExperimentalUnsignedTypes
internal class ContinuationTieGlyph: com.omnifret.gplayer.rendering.glyphs.TieGlyph
{
    private var _startTie: com.omnifret.gplayer.rendering.glyphs.TieGlyph
    
    public constructor(startTie: com.omnifret.gplayer.rendering.glyphs.TieGlyph)
        : super(startTie.slurEffectId, false){
        this._startTie = startTie
    }
    
    protected override fun lookupStartBeatRenderer(): com.omnifret.gplayer.rendering.LineBarRenderer{
        return (this.renderer as com.omnifret.gplayer.rendering.LineBarRenderer)
    }
    
    protected override fun lookupEndBeatRenderer(): com.omnifret.gplayer.rendering.LineBarRenderer{
        return (this.renderer as com.omnifret.gplayer.rendering.LineBarRenderer)
    }
    
    protected override fun shouldDrawBendSlur(): Boolean{
        return false
    }
    
    protected override fun calculateTieDirection(): com.omnifret.gplayer.rendering.utils.BeamDirection{
        return this._startTie.tieDirection
    }
    
    protected override fun calculateStartY(): Double{
        return this._startTie.calculateMultiSystemSlurY(this.renderer)
    }
    
    protected override fun caclculateEndY(): Double{
        return this.calculateStartY()
    }
    
    protected override fun calculateStartX(): Double{
        return this.renderer.staff!!.barRenderers[(0).toInt()].x
    }
    
    protected override fun calculateEndX(): Double{
        var last: com.omnifret.gplayer.rendering.BarRendererBase = this.renderer.staff!!.barRenderers[(this.renderer.staff!!.barRenderers.length - (1.0).toDouble()).toInt()]
        return last.x + last.width
    }
    
}

